import 'package:flutter/material.dart';class AuthTextField extends StatelessWidget {  final String label;  final String hint;  final IconData icon;  final bool obscure;  final TextInputType keyboardType;  final String? errorText;  final ValueChanged<String>? onChanged;  final Widget? suffix;  const AuthTextField({    super.key,    required this.label,    required this.hint,    required this.icon,    this.obscure = false,    this.keyboardType = TextInputType.text,    this.errorText,    this.onChanged,    this.suffix,  });  @override  Widget build(BuildContext context) {    return Column(      crossAxisAlignment: CrossAxisAlignment.start,      children: [        Text(          label,          style: const TextStyle(            fontSize: 14,            fontWeight: FontWeight.w600,            color: Color(0xFF374151),          ),        ),        const SizedBox(height: 6),        TextField(          obscureText: obscure,          keyboardType: keyboardType,          onChanged: onChanged,          decoration: InputDecoration(            hintText: hint,            prefixIcon: Icon(icon, size: 20, color: const Color(0xFF9CA3AF)),            suffixIcon: suffix,            errorText: errorText,          ),        ),      ],    );  }}